function calculateCosts(inputs) {
  const { companySize, aiSystemRiskLevel, dataVolumeComplexity, regulatoryJurisdictionsCount, annualAIModelsDeployedOrUpdated, externalConsultingRequired, externalConsultingHourlyRate, avgInternalComplianceHourlyCost, annualEmployeeComplianceTrainingHours } = inputs;

  // --- Configuration Constants ---
  const baseCostRanges = {
    'small': { 'minimal': 50000, 'limited': 150000, 'high': 400000, 'unacceptable': 750000 },
    'medium': { 'minimal': 150000, 'limited': 400000, 'high': 1200000, 'unacceptable': 2500000 },
    'large': { 'minimal': 500000, 'limited': 1500000, 'high': 4000000, 'unacceptable': 8000000 }
  };

  const dataComplexityCostFactors = {
    'low': 20000,
    'medium': 75000,
    'high': 250000,
    'veryHigh': 700000
  };

  const modelAssessmentCostPerModel = {
    'minimal': 5000,
    'limited': 15000,
    'high': 50000,
    'unacceptable': 100000
  };

  const externalConsultingBaseHours = {
    'minimal': 40,
    'limited': 80,
    'high': 200,
    'unacceptable': 400
  };

  const jurisdictionMultiplierFactor = 0.20; // 20% increase for each additional jurisdiction beyond the first

  const companyEmployeeCounts = {
    'small': 30, // Average for small
    'medium': 150, // Average for medium
    'large': 750 // Average for large
  };

  const internalComplianceBaseHours = {
    'small': 300, 
    'medium': 1000, 
    'large': 3000
  }; // Base internal hours for compliance oversight

  // --- Calculation Steps ---
  let totalFinancialCost = 0;
  let totalOperationalHours = 0;

  // 1. Base Compliance Cost (including initial setup, documentation, basic policy)
  const baseCost = baseCostRanges[companySize][aiSystemRiskLevel];
  totalFinancialCost += baseCost;
  totalOperationalHours += internalComplianceBaseHours[companySize];

  // 2. Data Governance & Privacy Compliance Cost
  const dataCost = dataComplexityCostFactors[dataVolumeComplexity];
  totalFinancialCost += dataCost;
  totalOperationalHours += dataCost / 100; // Roughly converting cost to hours, assuming $100/hr for data specialists

  // 3. Jurisdictional Complexity Cost
  if (regulatoryJurisdictionsCount > 1) {
    const additionalJurisdictions = regulatoryJurisdictionsCount - 1;
    const jurisdictionCostIncrease = baseCost * (additionalJurisdictions * jurisdictionMultiplierFactor);
    totalFinancialCost += jurisdictionCostIncrease;
    totalOperationalHours += additionalJurisdictions * 100; // 100 hours per additional jurisdiction for legal review, adaptation
  }

  // 4. AI Model Lifecycle Compliance Cost (assessment, documentation, testing)
  if (annualAIModelsDeployedOrUpdated > 0) {
    const modelCostPerUnit = modelAssessmentCostPerModel[aiSystemRiskLevel];
    const modelLifecycleCost = annualAIModelsDeployedOrUpdated * modelCostPerUnit;
    totalFinancialCost += modelLifecycleCost;
    totalOperationalHours += annualAIModelsDeployedOrUpdated * (modelCostPerUnit / 200); // Rough conversion, high risk models take more hours
  }

  // 5. External Consulting Costs (if required)
  if (externalConsultingRequired) {
    const rate = externalConsultingHourlyRate || 350; // Default if not provided but required
    const baseExternalHours = externalConsultingBaseHours[aiSystemRiskLevel];
    const externalCost = baseExternalHours * rate;
    totalFinancialCost += externalCost;
    // External consulting hours are not added to internal operational hours
  }

  // 6. Internal Staff Operational & Training Costs
  const effectiveInternalHourlyCost = avgInternalComplianceHourlyCost || 75; // Default if not provided
  const totalEmployees = companyEmployeeCounts[companySize];
  const trainingHours = totalEmployees * annualEmployeeComplianceTrainingHours;
  const trainingCost = trainingHours * effectiveInternalHourlyCost;
  totalFinancialCost += trainingCost;
  totalOperationalHours += trainingHours;

  // Apply minimum cost floor for 'Unacceptable Risk' due to extreme scrutiny
  if (aiSystemRiskLevel === 'unacceptable') {
    const unacceptableRiskFloor = baseCostRanges[companySize]['unacceptable']; // Use its own base as a floor
    totalFinancialCost = Math.max(totalFinancialCost, unacceptableRiskFloor * 1.2); // 20% higher than its base cost
  }

  // Cap output to prevent unrealistic extremes, especially if inputs are very high or low
  totalFinancialCost = Math.min(totalFinancialCost, 100000000); // Max $100M
  totalOperationalHours = Math.min(totalOperationalHours, 500000); // Max 500,000 hours

  return {
    totalEstimatedFinancialCost: totalFinancialCost,
    estimatedAnnualOperationalHours: totalOperationalHours
  };
}
